import { Link, useLocation } from "react-router-dom";
import axiosClient from "../../api/axiosClient";
import "../../styles/";

const NAV_ITEMS = [
  { to: "/client",               icon: "🏠", label: "Главная"       },
  { to: "/client/create",        icon: "📦", label: "Новый заказ"  },
  { to: "/client/orders",        icon: "📑", label: "Мои заказы"   },
  { to: "/client/track",         icon: "📍", label: "Отслеживание" },
  { to: "/client/notifications", icon: "🔔", label: "Уведомления"  },
];

export default function ClientSidebar({ open, setOpen }) {
  const location = useLocation();

  const logout = async () => {
    try { await axiosClient.post("/auth/logout"); } catch {}
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
    <>
      <aside className={`csidebar ${open ? "csidebar--open" : "csidebar--collapsed"}`}>
        <div className="csidebar__header">
          <div className="csidebar__logo">
            {open ? (
              <>
                <span className="csidebar__logo-icon">🚚</span>
                <span className="csidebar__logo-text">Delivry</span>
              </>
            ) : (
              <span className="csidebar__logo-icon">🚚</span>
            )}
          </div>
        </div>

        <nav className="csidebar__nav">
          {NAV_ITEMS.map((item) => {
            const active = location.pathname === item.to ||
              (item.to !== "/client" && location.pathname.startsWith(item.to));
            return (
              <Link
                key={item.to}
                to={item.to}
                className={`csidebar__link ${active ? "csidebar__link--active" : ""}`}
              >
                <span className="csidebar__link-icon">{item.icon}</span>
                {open && <span className="csidebar__link-label">{item.label}</span>}
                {active && <span className="csidebar__link-dot" />}
              </Link>
            );
          })}
        </nav>

        <div className="csidebar__bottom">
          <Link to="/client/profile" className="csidebar__link">
            <span className="csidebar__link-icon">⚙</span>
            {open && <span className="csidebar__link-label">Профиль</span>}
          </Link>
          <button className="csidebar__logout" onClick={logout}>
            <span className="csidebar__link-icon">🚪</span>
            {open && <span className="csidebar__link-label">Выйти</span>}
          </button>
        </div>
      </aside>

      <button
        className="csidebar__toggle"
        onClick={() => setOpen(!open)}
        aria-label="toggle sidebar"
      >
        {open ? "◀" : "▶"}
      </button>
    </>
  );
}
